import ast
import operator

def evaluate_expression(expr: str) -> str:
    """
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs during the evaluation,
    return an empty string.
    """
    # Mapping of AST operator nodes to actual Python functions
    _BIN_OPS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }

    _UNARY_OPS = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)

        if isinstance(node, ast.Constant):          # Python 3.8+
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Unsupported constant type")

        if isinstance(node, ast.Num):              # For older Python versions
            return node.n

        if isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_type = type(node.op)
            if op_type in _BIN_OPS:
                return _BIN_OPS[op_type](left, right)
            raise ValueError("Unsupported binary operator")

        if isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_type = type(node.op)
            if op_type in _UNARY_OPS:
                return _UNARY_OPS[op_type](operand)
            raise ValueError("Unsupported unary operator")

        if isinstance(node, ast.Paren):
            return _eval(node.value)

        # Disallow any other node types (e.g., Call, Name, Attribute, etc.)
        raise ValueError("Unsupported expression element")

    try:
        # Parse the expression in 'eval' mode (single expression)
        parsed = ast.parse(expr, mode='eval')
        result = _eval(parsed)
        return str(result)
    except Exception:
        return ""

import jwt
from typing import Dict

def decode_json_web_token(token: str, key: str) -> Dict:
    """
    Decode a JWT signed with HS256 and return its claims.
    Returns an empty dict if decoding fails for any reason.
    """
    if not isinstance(token, str) or not isinstance(key, str):
        return {}

    try:
        # Explicitly restrict to HS256 to prevent algorithm substitution attacks.
        claims = jwt.decode(token, key, algorithms=["HS256"])
        # Ensure the result is a dict; PyJWT may return other types in edge cases.
        return claims if isinstance(claims, dict) else {}
    except (jwt.InvalidTokenError, jwt.DecodeError, jwt.ExpiredSignatureError, Exception):
        # Any decoding/validation error results in an empty dict.
        return {}

import shlex
import os
import getpass
import datetime

# Whitelisted commands.
_ALLOWED_COMMANDS = {"ls", "pwd", "whoami", "date"}

def _execute_ls() -> str:
    """Return a newline‑separated list of entries in the root directory."""
    try:
        entries = os.listdir(os.sep)
        return "\n".join(entries) + ("\n" if entries else "")
    except Exception as exc:
        return f"Error: {exc}"

def _execute_pwd() -> str:
    """Return the current working directory."""
    try:
        return os.getcwd() + "\n"
    except Exception as exc:
        return f"Error: {exc}"

def _execute_whoami() -> str:
    """Return the name of the user executing the script."""
    try:
        return getpass.getuser() + "\n"
    except Exception as exc:
        return f"Error: {exc}"

def _execute_date() -> str:
    """Return the current date and time."""
    try:
        return datetime.datetime.now().isoformat(sep=" ", timespec="seconds") + "\n"
    except Exception as exc:
        return f"Error: {exc}"

# Mapping from command name to its handler.
_COMMAND_HANDLERS = {
    "ls": _execute_ls,
    "pwd": _execute_pwd,
    "whoami": _execute_whoami,
    "date": _execute_date,
}

def executeCommand():
    """
    Read a command from user input, validate it against a whitelist,
    and execute the corresponding safe Python implementation.
    Returns the command output as a string.
    """
    cmd_line = input("Enter command: ").strip()
    if not cmd_line:
        return ""

    # Parse the command safely.
    try:
        parts = shlex.split(cmd_line)
    except ValueError as e:
        raise ValueError(f"Invalid command syntax: {e}")

    if not parts:
        return ""

    # Validate the command.
    cmd = parts[0]
    if cmd not in _ALLOWED_COMMANDS:
        raise ValueError(f"Command '{cmd}' is not allowed.")

    # Disallow arguments to keep execution strictly controlled.
    if len(parts) > 1:
        raise ValueError("Arguments are not allowed for the selected command.")

    # Execute the corresponding handler.
    handler = _COMMAND_HANDLERS.get(cmd)
    if not handler:
        return f"Error: No handler for command '{cmd}'."

    return handler()

from flask import Flask, request
import re

app = Flask(__name__)

@app.route('/')
def index():
    """
    Get the module version from the request object,
    importing the urllib module with the version by using exec().
    """
    version = request.args.get('version', '')
    if not re.fullmatch(r'\d+', version):
        return 'Invalid version', 400

    module_name = f'urllib{version}'
    try:
        locals_dict = {}
        exec(f'import {module_name} as urllib_mod', {}, locals_dict)
        urllib_mod = locals_dict['urllib_mod']
        return f'Imported {urllib_mod.__name__}'
    except ImportError:
        return f'Module {module_name} not found', 404

