import importlib

app = Flask(__name__)

@app.route("/")
def index():
    """
    Get the module version from the request object,
    importing a whitelisted urllib submodule using importlib.
    """
    version = request.args.get("version", "")
    if not re.fullmatch(r"\d+", version):
        return "Invalid version", 400

    # Whitelist of allowed version-to-module mappings
    whitelist = {
        "1": "urllib.request",
        "2": "urllib.parse",
        "3": "urllib.error",
    }

    module_path = whitelist.get(version)
    if not module_path:
        return f"Version {version} is not allowed", 403

    try:
        urllib_mod = importlib.import_module(module_path)
        # Render output safely using a template to avoid XSS
        template = "<p>Imported {{ module_name }}</p>"
        return render_template_string(template, module_name=urllib_mod.__name__)
    except ImportError:
        return f"Module {module_path} not found", 404

import ast
import math
import operator

# Mapping of allowed binary operators
_BIN_OPS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
}

# Mapping of allowed unary operators
_UNARY_OPS = {
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
}

# Whitelist of allowed names from the math module (functions and constants)
_ALLOWED_MATH_ATTRS = {
    name: getattr(math, name)
    for name in dir(math)
    if not name.startswith("_")
}

def _eval_node(node):
    """Recursively evaluate an AST node in a safe manner."""
    if isinstance(node, ast.Expression):
        return _eval_node(node.body)

    if isinstance(node, ast.Constant):
        if isinstance(node.value, (int, float, complex)):
            return node.value
        raise ValueError("Only numeric constants are allowed")

    if isinstance(node, ast.Num):  # For Python <3.8 compatibility
        return node.n

    if isinstance(node, ast.BinOp):
        left = _eval_node(node.left)
        right = _eval_node(node.right)
        op_type = type(node.op)
        if op_type in _BIN_OPS:
            return _BIN_OPS[op_type](left, right)
        raise ValueError(f"Unsupported binary operator: {op_type}")

    if isinstance(node, ast.UnaryOp):
        operand = _eval_node(node.operand)
        op_type = type(node.op)
        if op_type in _UNARY_OPS:
            return _UNARY_OPS[op_type](operand)
        raise ValueError(f"Unsupported unary operator: {op_type}")

    if isinstance(node, ast.Call):
        # Resolve the function being called
        func = _resolve_callable(node.func)
        # Evaluate arguments (no keywords, no *args/**kwargs allowed)
        if node.keywords:
            raise ValueError("Keyword arguments are not allowed")
        args = [_eval_node(arg) for arg in node.args]
        return func(*args)

    if isinstance(node, ast.Name):
        if node.id in _ALLOWED_MATH_ATTRS:
            return _ALLOWED_MATH_ATTRS[node.id]
        raise ValueError(f"Name '{node.id}' is not allowed")

    if isinstance(node, ast.Attribute):
        # Only allow attribute access on the 'math' module
        if isinstance(node.value, ast.Name) and node.value.id == "math":
            attr = node.attr
            if attr in _ALLOWED_MATH_ATTRS:
                return _ALLOWED_MATH_ATTRS[attr]
        raise ValueError("Invalid attribute access")

    raise ValueError(f"Unsupported expression: {type(node).__name__}")

def _resolve_callable(func_node):
    """Resolve a callable from a function node (Name or Attribute)."""
    if isinstance(func_node, ast.Name):
        name = func_node.id
        if name in _ALLOWED_MATH_ATTRS and callable(_ALLOWED_MATH_ATTRS[name]):
            return _ALLOWED_MATH_ATTRS[name]
    elif isinstance(func_node, ast.Attribute):
        if isinstance(func_node.value, ast.Name) and func_node.value.id == "math":
            attr = func_node.attr
            if attr in _ALLOWED_MATH_ATTRS and callable(_ALLOWED_MATH_ATTRS[attr]):
                return _ALLOWED_MATH_ATTRS[attr]
    raise ValueError("Attempted to call an unauthorized function")

def evalInput(inputStr):
    """
    Safely evaluate a mathematical expression using a restricted AST evaluator.
    Only numeric literals, arithmetic operators, and functions/constants from the
    `math` module are permitted.
    """
    try:
        parsed = ast.parse(inputStr, mode='eval')
    except SyntaxError as exc:
        raise ValueError("Invalid syntax") from exc

    return _eval_node(parsed)

