import io

class SafeUnpickler(pickle.Unpickler):
    _SAFE_BUILTINS = {
        "list", "dict", "set", "tuple", "str",
        "int", "float", "bool", "bytes"
    }

    def find_class(self, module, name):
        if module == "builtins" and name in self._SAFE_BUILTINS:
            return getattr(__builtins__, name)
        raise pickle.UnpicklingError(f"Forbidden class: {module}.{name}")

def getPickleData(pickled):
    """
    Return deserialized data safely.
    """
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled must be a bytes-like object")
    return SafeUnpickler(io.BytesIO(pickled)).load()

import json
from django.conf.urls import url

def getPickleData(pickled):
    """
    Return deserialized data safely using JSON.
    """
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled must be a bytes-like object")
    try:
        # Decode bytes to string assuming UTF-8 encoding
        text = pickled.decode("utf-8")
    except Exception as exc:
        raise ValueError("Failed to decode input as UTF-8") from exc

    try:
        data = json.loads(text)
    except json.JSONDecodeError as exc:
        raise ValueError("Invalid JSON data") from exc

    return data

import _pickle as cPickle
import base64

def confirmAuth(headers):
    """
    Extracts the 'AuthToken' from the provided headers, decodes it from base64,
    unpickles it using cPickle, and returns the token's data if the token is
    marked as valid. Returns None for missing, malformed, or invalid tokens.
    """
    token_b64 = headers.get('AuthToken')
    if not token_b64:
        return None
    try:
        token_bytes = base64.b64decode(token_b64, validate=True)
        token_obj = cPickle.loads(token_bytes)
    except Exception:
        return None

    if isinstance(token_obj, dict) and token_obj.get('valid'):
        return token_obj.get('data')
    return None

from flask import Flask, request, jsonify, abort
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    """
    Get YAML data from request, parse it safely, and return it as JSON.
    """
    # Ensure the request has a body
    if not request.data:
        abort(400, description="No YAML data provided")

    # Decode request data as text (UTF-8)
    yaml_text = request.get_data(as_text=True)

    try:
        # Use safe_load to avoid executing arbitrary code
        parsed = yaml.safe_load(yaml_text)
    except yaml.YAMLError as e:
        abort(400, description=f"Invalid YAML: {e}")

    # If parsing results in None (e.g., empty document), treat as empty dict
    if parsed is None:
        parsed = {}

    # Return the parsed data as JSON
    return jsonify(parsed)
